const body = $json.body ?? $json;
const allowedSources = ['99acres', 'housing', 'housing,99acres'];
const allowedModes = ['daily', 'bootstrap'];

const source = String(body.source ?? body.sources ?? '99acres').trim();
const mode = String(body.mode ?? 'daily').trim();
const dryRun = body.dryRun === true || body.dryRun === 'true';

if (!allowedSources.includes(source)) {
  throw new Error(`Unsupported source. Use one of: ${allowedSources.join(', ')}`);
}

if (!allowedModes.includes(mode)) {
  throw new Error(`Unsupported mode. Use one of: ${allowedModes.join(', ')}`);
}

const sourceArg = source.includes(',') ? `--sources=${source}` : `--source=${source}`;
const dryArg = dryRun ? ' --dry-run' : '';
const command = `cmd /c "cd /d C:\\SpringBoot\\WorkSpace\\re-scraper && npm run n8n -- ${sourceArg} --mode=${mode}${dryArg}"`;

return [{
  source,
  mode,
  dryRun,
  command,
  requestedAt: new Date().toISOString(),
}];

const stdout = String($json.stdout ?? '').trim();
const stderr = String($json.stderr ?? '').trim();
const exitCode = Number($json.exitCode ?? 0);

let parsed;
try {
  parsed = stdout ? JSON.parse(stdout) : null;
} catch (error) {
  parsed = {
    ok: false,
    parseError: error.message,
    rawStdout: stdout,
  };
}

return [{
  ok: parsed?.ok === true && exitCode === 0,
  exitCode,
  stderr,
  result: parsed,
  completedAt: new Date().toISOString(),
}];
